/**
 * agents/conductor.ts — Phase C lightweight orchestrator
 *
 * Vertical-slice orchestrator. Given a user message + chat options, it
 * runs a deterministic graph of agent steps and emits public-safe
 * AgentEvents through the supplied `emit` callback. The actual draft
 * text is produced by composeAnswer() — for this slice the answer is a
 * Thai-led structured plan generated by deterministic templates so the
 * vertical slice is testable without an LLM round-trip. Real Ollama
 * streaming through the Concierge is C-3.5 follow-up.
 *
 * The orchestrator never emits private reasoning. Every event passes
 * through the public-safe gate before being written.
 */

import { randomUUID } from "node:crypto";
import * as fsPromises from "node:fs/promises";
import * as nodePath from "node:path";
import {
  newEnvelope,
  type AgentEvent,
  type AgentEventType,
  type AgentId,
} from "./events";
import { checkAgentEventSafe } from "./eventGuard";
import { selectProvider, type ChatMode } from "../providers/router";
import { callProvider } from "../services/providerAdapter";
import { listProviders } from "../providers/registry";
import {
  classifyIntent,
  type ChatIntent,
} from "../services/intentClassifier";
import { checkNaturalness } from "../services/naturalnessGuard";
import { dispatchAgents, synthesizeAnswer, type AgentRunMode } from "./parallelDispatch";
import { dispatchTool } from "./toolDispatch";
import { dispatchMother } from "./motherDispatch";
import type { GuestLimits } from "../middleware/guestLimiter";
import { sessionMemory, type MemoryDomain } from "../services/sessionMemory";
import { disambiguateWithSessionMemory } from "../services/memoryRagHook";
import {
  buildSystemInventoryAnswer,
  looksLikeSystemInventoryQuestion,
} from "../services/systemInventory";

export interface ConductorOptions {
  message: string;
  history?: Array<{ sender: "user" | "ai"; text: string }>;
  sessionId?: string;
  clientMessageId?: string;
  preferredMode?: ChatMode;
  preferredProviderId?: string;
  responseMode?: AgentRunMode;
  thinkingMode?: boolean;
  toolHint?: string;
  userTier?: "guest" | "user" | "admin";
  capabilityLevel?: number;
  guestLimits?: GuestLimits;
}

export type EmitFn = (ev: AgentEvent) => void;

export interface RunResult {
  runId: string;
  messageId: string;
  finalText: string;
  intent: ChatIntent;
  providerId: string | null;
  model: string | null;
  events: number;
}

interface ComposeContext {
  intent: ChatIntent;
  query: string;
  facts: string[];
}

function composeAnswer(ctx: ComposeContext): string {
  switch (ctx.intent) {
    case "greeting":
      return composeGreetingAnswer();
    case "system-inventory":
      return "";
    case "planning-broad":
      return composePlanningBroadAnswer(ctx.query, ctx.facts);
    case "weather":
      return composeWeatherAnswer(ctx.query, ctx.facts);
    case "datetime":
      return composeDateTimeAnswer();
    case "calc":
      return composeCalcAnswer(ctx.query);
    case "code":
      return composeCodeAnswer(ctx.query);
    case "map":
      return composeMapAnswer(ctx.query);
    case "evidence":
      return "";
    case "knowledge":
      return "";
    case "factual":
      return "";
    default:
      return composeGeneralAnswer(ctx.query);
  }
}

function normalizeResponseMode(opts: ConductorOptions): AgentRunMode {
  if (opts.thinkingMode === true) return "thinking";
  return opts.responseMode === "thinking" ? "thinking" : "normal";
}

function getRuntimeMcpClient(): any | null {
  try {
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    return require("../routes/api/chat")?.mcpClient ?? null;
  } catch {
    return null;
  }
}

function composeDateTimeAnswer(): string {
  const now = new Date();
  const bkk = new Date(now.getTime() + 7 * 60 * 60 * 1000);
  const dayNames = ["วันอาทิตย์", "วันจันทร์", "วันอังคาร", "วันพุธ", "วันพฤหัสบดี", "วันศุกร์", "วันเสาร์"];
  const monthNames = [
    "มกราคม",
    "กุมภาพันธ์",
    "มีนาคม",
    "เมษายน",
    "พฤษภาคม",
    "มิถุนายน",
    "กรกฎาคม",
    "สิงหาคม",
    "กันยายน",
    "ตุลาคม",
    "พฤศจิกายน",
    "ธันวาคม",
  ];
  const weekday = dayNames[bkk.getUTCDay()];
  const day = bkk.getUTCDate();
  const month = monthNames[bkk.getUTCMonth()];
  const yearBe = bkk.getUTCFullYear() + 543;
  const hh = String(bkk.getUTCHours()).padStart(2, "0");
  const mm = String(bkk.getUTCMinutes()).padStart(2, "0");
  return `ขณะนี้ที่ประเทศไทยคือ ${weekday}ที่ ${day} ${month} พ.ศ. ${yearBe} เวลา ${hh}:${mm} น. (UTC+7)`;
}

function composeGreetingAnswer(): string {
  const greetings = [
    "สวัสดีครับ มีอะไรให้ช่วยไหม?",
    "สวัสดีครับ วันนี้ต้องการทราบอะไรเป็นพิเศษ?",
    "ยินดีช่วยเสมอครับ บอกได้เลย",
  ];
  return greetings[Math.floor(Math.random() * greetings.length)];
}

function composePlanningBroadAnswer(query: string, facts: string[]): string {
  // Phase C.05 — use the actual query so the template is query-aware,
  // not a hardcoded seminar boilerplate that ignores what was asked.
  const factLine =
    facts.length > 0
      ? facts.map((f) => `• ${f}`).join("\n")
      : "• กำลังดึงข้อมูลจากเครื่องมือหลายชุดพร้อมกัน";
  const trimQ = query.trim().slice(0, 120);
  return [
    `โจทย์: "${trimQ}"`,
    "",
    "**กำลังวิเคราะห์หลายปัจจัยพร้อมกัน:**",
    "• สภาพอากาศ + พยากรณ์ฝนรายสัปดาห์ (กรมอุตุฯ / NWP)",
    "• ข้อมูลพื้นที่ + ระยะทางการเดินทาง (Thai Geo)",
    "• MDES วิเคราะห์ตามโจทย์เฉพาะนี้",
    "",
    "**ข้อมูลที่ดึงมาแล้ว:**",
    factLine,
    "",
    "ผลสรุปจะปรากฏเมื่อรวบรวมข้อมูลครบ",
  ].join("\n");
}

function composeWeatherAnswer(query: string, facts: string[]): string {
  const factLine = facts.length > 0 ? facts.map((f) => `• ${f}`).join("\n") : "";
  return [
    "สรุปอากาศตามที่ถามครับ",
    factLine,
    "",
    "ต้องการรายชั่วโมงหรือเฉพาะอำเภอ บอกเพิ่มได้เลยครับ",
  ]
    .filter(Boolean)
    .join("\n");
}

function composeCalcAnswer(_query: string): string {
