}

/**
 * Safe emit wrapper — runs the public-safe gate, suppresses on failure
 * and emits a clean fallback event instead. Returns true if the original
 * was emitted, false if it was rejected.
 */
function safeEmit(emit: EmitFn, ev: AgentEvent, expectedToolUsage: boolean): boolean {
  const guard = checkAgentEventSafe(ev, { expectedToolUsage });
  if (!guard.ok) {
    const fallback: AgentEvent = newEnvelope({
      runId: ev.runId,
      messageId: ev.messageId,
      type: "fallback",
      publicSummary: "เหตุการณ์ภายในถูกปรับให้ปลอดภัยก่อนเผยแพร่",
      agentId: "conductor",
    });
    fallback.fallbackReason = guard.reason;
    emit(fallback);
    return false;
  }
  emit(ev);
  return true;
}

function emitStarted(
  emit: EmitFn,
  runId: string,
  messageId: string,
  agentId: AgentId,
  publicSummary: string,
  expectedToolUsage: boolean
): void {
  const ev = newEnvelope({
    runId,
    messageId,
    type: "agent_started",
    publicSummary,
    agentId,
  });
  safeEmit(emit, ev, expectedToolUsage);
}

function emitFact(
  emit: EmitFn,
  runId: string,
  messageId: string,
  agentId: AgentId,
  publicSummary: string,
  confidence: number,
  expectedToolUsage: boolean
): void {
  const ev = newEnvelope({
    runId,
    messageId,
    type: "fact_found",
    publicSummary,
    agentId,
  });
  ev.confidence = confidence;
  safeEmit(emit, ev, expectedToolUsage);
}

