  | "tool-use"
  | "fast-cheap"
  | "hard-reasoning"
  | "grounding-critic"
  | "general-purpose"
  | "ultra-reasoning"
  | "complex-architecture"
  | "code-review"
  | "math"
  | "multimodal"
  | "culture-aware";

export type PrivacyLevel = "public" | "internal" | "confidential";

export type HealthStatus = "unknown" | "healthy" | "degraded" | "down";

