  enabled: boolean;
  privacyLevel: PrivacyLevel;
  timeoutMs: number;
  maxTokens?: number;
  temperature?: number;
  healthStatus: HealthStatus;
  lastHealthCheckAt?: string;
}

/** Project to public view — drops both apiKeyRef and apiKeyEncrypted. */
